#include <iostream>
#include <vector>
#include <memory>

class Counter {
private:
    static int s_count;

public:
    Counter() {
        s_count++;
    }

    ~Counter() {
        s_count--;
    }

    static int getTotalCount() {
        return s_count;
    }
};

int Counter::s_count = 0;

int main() {
    std::cout << "Initial active counters: " << Counter::getTotalCount() << std::endl;

    {
        Counter c1;
        std::cout << "After creating c1: " << Counter::getTotalCount() << std::endl;

        Counter c2;
        std::cout << "After creating c2: " << Counter::getTotalCount() << std::endl;
    }
    std::cout << "After c1 and c2 go out of scope: " << Counter::getTotalCount() << std::endl;

    std::vector<Counter> counterVector;
    counterVector.reserve(3);
    counterVector.emplace_back();
    counterVector.emplace_back();
    std::cout << "After adding 2 objects to vector: " << Counter::getTotalCount() << std::endl;

    counterVector.clear();
    std::cout << "After clearing vector: " << Counter::getTotalCount() << std::endl;

    Counter* c3 = new Counter();
    std::cout << "After dynamically allocating c3: " << Counter::getTotalCount() << std::endl;

    std::unique_ptr<Counter> c4 = std::make_unique<Counter>();
    std::cout << "After creating c4 with unique_ptr: " << Counter::getTotalCount() << std::endl;

    delete c3;
    std::cout << "After deleting c3: " << Counter::getTotalCount() << std::endl;

    std::cout << "Final active counters before main exits: " << Counter::getTotalCount() << std::endl;

    return 0;
}
